    // Instructions that are part of a recurrence are not uniform.
    if (isInductionVariable(I) || isRecurrence(I))
      return false;
    // The instruction is uniform if all of its operands are uniform.
    for (unsigned i = 0, e = I->getNumOperands(); i != e; ++i)
      if (!isUniform(I->getOperand(i)))
        return false;
  }
  return true;
}
```
